function e(e,t){return e?.response?.data?.message||(e?.code===`ERR_NETWORK`?`Cannot reach the API. Check your internet connection or backend URL, then try again.`:e?.response?.status===404?`Auth API route was not found. Check that the frontend is pointing to the correct backend URL.`:e?.response?.status===500?`The backend returned a server error. Check the backend terminal for details.`:String(e?.message||``).toLowerCase().includes(`cors`)?`Login was blocked by CORS. Restart the backend with the updated local origin settings.`:t)}export{e as t};